if (!function_exists('sendPayrollReportByEmail')) {
    /**
     * Generates the Excel, writes it to temp, sends email with it as attachment,
     * then cleans up the file.
     */
    function sendPayrollReportByEmail(PDO $pdo, array $reportData, array $recipients, string $aiSummary = ''): bool
    {
        if (empty($recipients)) {
            error_log('[payroll_report] No recipients configured');
            return false;
        }

        $html = generatePayrollReportHTML($reportData, $aiSummary);

        // Write Excel to temp path
        $excelPath = null;
        try {
            $excelPath = writePayrollExcelFile($reportData);
        } catch (Throwable $e) {
            error_log('[payroll_report] Could not create Excel: ' . $e->getMessage());
            // Continue without attachment — body still has a full summary
        }

        require_once __DIR__ . '/email_functions.php';
        $result = sendDailyPayrollReport($html, $recipients, $reportData, $excelPath);

        // Clean up temp file
        if ($excelPath && file_exists($excelPath)) {
            @unlink($excelPath);
        }

        if ($result['success']) {
            error_log('[payroll_report] Sent: ' . $result['message']);
            return true;
        }
        error_log('[payroll_report] Failed: ' . $result['message']);
        return false;
    }
}
